/**
 * 根据体重对单项有氧运动进行线性插值，计算出每小时（或每走一万步）的能耗 (kcal)
 */
export function interpolateExpenditure(activity, weight) {
  if (weight <= 50) {
    const v0 = activity.expenditures[0];
    const v1 = activity.expenditures[1];
    const ratio = (weight - 50) / 5;
    const val = v0 + ratio * (v1 - v0);
    return Math.max(0, Math.round(val));
  }
  if (weight >= 120) {
    const v13 = activity.expenditures[13];
    const v14 = activity.expenditures[14];
    const ratio = (weight - 120) / 5;
    const val = v14 + ratio * (v14 - v13);
    return Math.max(0, Math.round(val));
  }

  // 寻找所在的体重区间
  for (let i = 0; i < WEIGHT_LEVELS.length - 1; i++) {
    const w0 = WEIGHT_LEVELS[i];
    const w1 = WEIGHT_LEVELS[i + 1];
    if (weight >= w0 && weight <= w1) {
      const v0 = activity.expenditures[i];
      const v1 = activity.expenditures[i + 1];
      const ratio = (weight - w0) / (w1 - w0);
      const val = v0 + ratio * (v1 - v0);
      return Math.max(0, Math.round(val));
    }
  }
  return 0;
}

/**
 * 计算给定时间（分钟）或步数下的有氧运动消耗卡路里
 */
export function getAerobicKcal(category, subtype, weight, durationOrSteps) {
  const activity = AEROBIC_DATA.find(
    (a) => a.category === category && a.subtype === subtype
  );
  if (!activity) return 0;

  if (subtype === '每走一万步') {
    const base = interpolateExpenditure(activity, weight);
    return Math.max(0, Math.round(base * (durationOrSteps / 10000)));
  } else {
    const base = interpolateExpenditure(activity, weight);
    return Math.max(0, Math.round(base * (durationOrSteps / 60)));
  }
}

/**
 * 格式化有氧运动子分类/强度，以便在下拉列表中更友好地显示
 */
export function formatSubtypeDisplay(sub, category) {
  if (!sub) return '';
  const num = Number(sub);
  if (!isNaN(num)) {
    const cleanCat = category.split('\n')[0].split('*')[0].trim();
    if (cleanCat === '跑步') {
      return `速度 ${num} km/h`;
    }
    if (cleanCat === '户外骑行') {
      return `时速 ${num} km/h`;
    }
    if (cleanCat === '游泳') {
      return `速度 ${Math.round(num * 100) / 100} km/h`;
    }
    return `强度/速度: ${num}`;
  }
  return sub;
}
